	.PROC	M680002	.REF	SMAKY	.LOC	0START:	LIB	?BUZZ	LIB	?AFTIM	.B	NOCURS,0	.EVEN	LIB	?BUCAR	LOAD.W	D3,#10	SWAP.W	D3	LOAD.W	D3,#10	LOAD.W	D1,#1010$:	PUSHM.L	D3,D4	SUB.W	D3,#2	LOAD.W	D4,#200	SWAP.W	D4	CLR.W	D4	LOAD.W	D2,#SETDOT	LIB	?DRSEG	POPM.L	D3,D4	CALL	JOLI	PUSHM.L	D3,D4	SUB.W	D3,#2	LOAD.W	D4,#200	SWAP.W	D4	CLR.W	D4	LOAD.W	D2,#SETDOT	LIB	?DRSEG	POPM.L	D3,D4	INC.W	D3	DEC.W	D1	JUMP,NE 10$	LIB	?NOBUCAR	LIB	?BUZZ	EXITJOLI:	LOAD.W	D2,#SETDOT	CALL	ESSAI	LOAD.W	D2,#CLRDOT	CALL	ESSAI	LOAD.W	D2,#INVDOT	CALL	ESSAI	LOAD.W	D2,#INVDOT	CALL	ESSAI	RETESSAI:	PUSHM.L	D1..D4	LOAD.L	D4,#400	LOAD.W	D1,#10010$:	PUSH.L	D3	LIB	?DRSEG	POP.L	D3	ADD.L	D3,#H'10000*2	INC.W	D4	DEC.W	D1	JUMP,NE 10$	POPM.L	D1..D4	RET	.END	START